<?php
/** Expense ledger with cost attribution. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';requireAuth();enforceModuleAccess('expenses');$rows=getDb()->query('SELECT e.*,v.registration_number,t.trip_number,c.name category_name FROM expenses e LEFT JOIN vehicles v ON v.id=e.vehicle_id LEFT JOIN trips t ON t.id=e.trip_id LEFT JOIN expense_categories c ON c.id=e.expense_category_id WHERE e.deleted_at IS NULL ORDER BY e.expense_date DESC')->fetchAll();$pageTitle='Expenses';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';?><main class="main-content expense-module"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><div><h1 class="page-title">Expense management</h1><p class="page-subtitle">Control operational spending by vehicle, trip, and category.</p></div><a class="btn btn-primary" href="add.php">Add expense</a></section><section class="card table-card"><div class="table-responsive"><table class="expense-table"><thead><tr><th>Expense</th><th>Vehicle</th><th>Trip</th><th>Category</th><th>Vendor</th><th>Amount</th><th>Date</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['title'])?></strong><small><?=e($r['expense_code']?:'#'.$r['id'])?></small></td><td><?=e($r['registration_number']?:'—')?></td><td><?=e($r['trip_number']?:'—')?></td><td><?=e($r['category_name']?:$r['expense_type'])?></td><td><?=e($r['vendor_name']?:'—')?></td><td><?=e(formatCurrency((float)$r['amount']))?></td><td><?=e(formatDate($r['expense_date']))?></td><td><span class="badge badge-success"><?=e($r['status'])?></span></td><td><a href="view.php?id=<?=$r['id']?>"><i class="fa fa-eye"></i></a></td></tr><?php endforeach;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
